/**
 * Every error that can cross the boundary. Internal `anyhow`/engine errors are
 * mapped into one of these variants; the underlying error is never leaked.
 */
sealed class SdkException: kotlin.Exception() {
    
    /**
     * An operation needing a published record was called before `register`.
     */
    class NotRegistered(
        ) : SdkException() {
        override val message
            get() = ""
    }
    
    /**
     * A network/transport/server failure talking to the directory or queue.
     */
    class Network(
        
        /**
         * A human-readable description (no secrets).
         */
        val `msg`: kotlin.String
        ) : SdkException() {
        override val message
            get() = "msg=${ `msg` }"
    }
    
    /**
     * A local storage (filesystem/serialization) failure.
     */
    class Storage(
        
        /**
         * A human-readable description (no secrets).
         */
        val `msg`: kotlin.String
        ) : SdkException() {
        override val message
            get() = "msg=${ `msg` }"
    }
    
    /**
     * A cryptographic failure (sealing/opening/identity).
     */
    class Crypto(
        
        /**
         * A human-readable description (no secrets).
         */
        val `msg`: kotlin.String
        ) : SdkException() {
        override val message
            get() = "msg=${ `msg` }"
    }
    
    /**
     * A caller-supplied argument was invalid (e.g. a malformed handle).
     */
    class InvalidInput(
        
        /**
         * A human-readable description.
         */
        val `msg`: kotlin.String
        ) : SdkException() {
        override val message
            get() = "msg=${ `msg` }"
    }
    
    /**
     * A peer's wallet no longer matches what we pinned/verified — treat as a
     * possible impersonation and re-verify out of band.
     */
    class IdentityChanged(
        
        /**
         * The affected peer handle.
         */
        val `handle`: kotlin.String
        ) : SdkException() {
        override val message
            get() = "handle=${ `handle` }"
    }
    

    companion object ErrorHandler : UniffiRustCallStatusErrorHandler<SdkException> {
        override fun lift(error_buf: RustBuffer.ByValue): SdkException = FfiConverterTypeSdkError.lift(error_buf)
    }

    
}

/**
 * @suppress
 */
public object FfiConverterTypeSdkError : FfiConverterRustBuffer<SdkException> {
    override fun read(buf: ByteBuffer): SdkException {
        

        return when(buf.getInt()) {
            1 -> SdkException.NotRegistered()
            2 -> SdkException.Network(
                FfiConverterString.read(buf),
                )
            3 -> SdkException.Storage(
                FfiConverterString.read(buf),
                )
            4 -> SdkException.Crypto(
                FfiConverterString.read(buf),
                )
            5 -> SdkException.InvalidInput(
                FfiConverterString.read(buf),
                )
            6 -> SdkException.IdentityChanged(
                FfiConverterString.read(buf),
                )
            else -> throw RuntimeException("invalid error enum value, something is very wrong!!")
        }
    }

    override fun allocationSize(value: SdkException): ULong {
        return when(value) {
            is SdkException.NotRegistered -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
            )
            is SdkException.Network -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.`msg`)
            )
            is SdkException.Storage -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.`msg`)
            )
            is SdkException.Crypto -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.`msg`)
            )
            is SdkException.InvalidInput -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.`msg`)
            )
            is SdkException.IdentityChanged -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.`handle`)
            )
        }
    }

    override fun write(value: SdkException, buf: ByteBuffer) {
        when(value) {
            is SdkException.NotRegistered -> {
                buf.putInt(1)
                Unit
            }
            is SdkException.Network -> {
                buf.putInt(2)
                FfiConverterString.write(value.`msg`, buf)
                Unit
            }
            is SdkException.Storage -> {
                buf.putInt(3)
                FfiConverterString.write(value.`msg`, buf)
                Unit
            }
            is SdkException.Crypto -> {
                buf.putInt(4)
                FfiConverterString.write(value.`msg`, buf)
                Unit
            }
            is SdkException.InvalidInput -> {
                buf.putInt(5)
                FfiConverterString.write(value.`msg`, buf)
                Unit
            }
            is SdkException.IdentityChanged -> {
                buf.putInt(6)
                FfiConverterString.write(value.`handle`, buf)
                Unit
            }
        }.let { /* this makes the `when` an expression, which ensures it is exhaustive */ }
    }

}



